import { NativeModule } from 'react-native';

export interface UnicoCredentials {
  projectNumber: string;
  projectId: string;
  mobileSdkAppId: string;
  hostInfo: string;
  bundleIdentifier: string;
  hostKey: string;
}

export interface UnicoCheckModule extends NativeModule {
  configure(credentials: UnicoCredentials): void;
  callSmartCamera(): void;
  callDefaultCamera(): void;
  callLivenessCamera(): void;
  callDocument(): void;
  callDocumentFrontCamera(): void;
  callDocumentBackCamera(): void;
  callIdentityFrontCamera(): void;
  callIdentityBackCamera(): void;
}

export type UnicoEventsType = 'onSuccess' | 'onError' | 'onSuccessJWT';

export interface UnicoNativeEventEmitter {
  addListener: (eventType: UnicoEventsType, listener: UnicoEventEmitterCallback) => void;
  removeAllListeners: (eventType: UnicoEventsType) => void;
}

export enum UnicoErrorCode {
  SUCCESS = 0,
  TIMEOUT = 1,
  CLOSED_BY_USER = 2,
  SESSION_TIMEOUT = 3,
  FACE_RECOGNITION_TIMEOUT = 4,
  OTHER_ERROR = 5,
}

export type UnicoEventEmitterCallback = (data: { result: string; code: UnicoErrorCode }) => void;

