import { AppReducers } from '../../../redux/reducers/Models';

interface UseProductAndContentQueryProps {
  requestExemptionEligibility: () => void;
  requestContents: () => void;
  productRequest: () => void;
  requestActivities: () => void;
}

export type AppReducersProps = Pick<
  AppReducers,
  | 'contentsReducer'
  | 'productsReducer'
  | 'exemptionEligibilityReducer'
  | 'featuresReducer'
>;

export type HandleCheckExemptionEligibilityProps = (
  props: AppReducersProps,
) => { hasExemptionEligible: boolean; hasProductsDataAccount: boolean };

interface UseProductAndContentQueryReturn {
  hasExemptionEligible: boolean;
  isLoadingExemptionEligibility: boolean;
  isLoadingProducts: boolean;
  isErrorProductsAndContents: boolean;
  requestAll: () => void;
  handleCheckExemptionEligibility: HandleCheckExemptionEligibilityProps;
}

