     1→import { useCallback, useState } from 'react';
     2→import { Platform, Share as RNShare } from 'react-native';
     3→import RNFS from 'react-native-fs';
     4→import Share from 'react-native-share';
     5→import { useDispatch } from 'react-redux';
     6→
     7→import {
     8→  DownloadInvoiceActions,
     9→  DownloadInvoiceTypes,
    10→} from '../redux/ducks/downloadInvoice';
    11→
    12→export interface UseShareMediaReturn {
    13→  handleShare: (date: string) => Promise<void>;
    14→  isLoading: boolean;
    15→  isError: boolean;
    16→}
    17→
    18→export type FileType = 'pdf' | 'png' | 'jpg' | 'jpeg';
    19→
    20→const urlEncoderType: Record<FileType, string> = {
    21→  pdf: 'application/pdf',
    22→  jpeg: 'image/jpeg',
    23→  jpg: 'image/jpg',
    24→  png: 'image/png',
    25→};
    26→
    27→export const useShareMedia = ({
    28→  fileName,
    29→  fileType,
    30→}: {
    31→  fileName: string;
    32→  fileType: FileType;
    33→}): UseShareMediaReturn => {
    34→  const [isError, setIsError] = useState(false);
    35→  const [isLoading, setIsLoading] = useState(false);
    36→
    37→  const dispatch = useDispatch();
    38→
    39→  const invoiceDownloadRequest = useCallback<
    40→    DownloadInvoiceActions['downloadInvoiceRequest']
    41→  >(
    42→    (cpf, date, callBack, openFile) =>
    43→      dispatch({
    44→        type: DownloadInvoiceTypes.REQUEST,
    45→        cpf,
    46→        date,
    47→        callBack,
    48→        openFile,
    49→      }),
    50→    [],
    51→  );
    52→
    53→  const handleShare = async (date: string) => {
    54→    setIsLoading(true);
    55→
    56→    try {
    57→      const path = `${RNFS.DocumentDirectoryPath}/${fileName}.${fileType}`;
    58→
    59→      const content = {
    60→        title: fileName,
    61→        message: fileName,
    62→      };
    63→
    64→      invoiceDownloadRequest(
    65→        '',
    66→        date,
    67→        async ({ base64 }) => {
    68→          await RNFS.writeFile(path, base64, 'base64').catch(error => {
    69→            throw new Error(`WriteFile error: ${error}`);
    70→          });
    71→
    72→          if (Platform.OS === 'android') {
    73→            await Share.open({
    74→              ...content,
    75→              url: `data:${urlEncoderType[fileType]};base64,${base64}`,
    76→            });
    77→          }
    78→          await RNShare.share({
    79→            ...content,
    80→            url: encodeURIComponent(path),
    81→          });
    82→        },
    83→        false,
    84→      );
    85→
    86→      setIsError(false);
    87→    } catch (err) {
    88→      if (err instanceof Error && err.message === 'User did not share') {
    89→        setIsError(false);
    90→        return;
    91→      }
    92→
    93→      setIsError(true);
    94→    } finally {
    95→      setIsLoading(false);
    96→    }
    97→  };
    98→
    99→  return { handleShare, isLoading, isError };
   100→};
